"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { cn } from "@/lib/utils"

// --- Root Context ---

type StepperContextValue = {
  value: number
  onValueChange: (value: number) => void
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper>")
  }
  return context
}

// --- Item Context ---

type StepperItemContextValue = {
  step: number
  isActive: boolean
  isCompleted: boolean
}

const StepperItemContext =
  React.createContext<StepperItemContextValue | null>(null)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem>")
  }
  return context
}

// --- Components ---

type StepperProps = {
  value?: number
  defaultValue?: number
  onValueChange?: (value: number) => void
  orientation?: "horizontal" | "vertical"
} & Omit<React.ComponentProps<"div">, "defaultValue">

function Stepper({
  value: valueProp,
  defaultValue = 1,
  onValueChange,
  orientation = "horizontal",
  className,
  ...props
}: StepperProps) {
  const [valueState, setValueState] = React.useState(defaultValue)
  const isControlled = valueProp !== undefined
  const value = isControlled ? valueProp : valueState

  const handleValueChange = React.useCallback(
    (newValue: number) => {
      if (!isControlled) {
        setValueState(newValue)
      }
      onValueChange?.(newValue)
    },
    [isControlled, onValueChange]
  )

  return (
    <StepperContext.Provider
      value={{ value, onValueChange: handleValueChange, orientation }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn("group/stepper flex flex-col gap-4", className)}
        {...props}
      />
    </StepperContext.Provider>
  )
}

function StepperList({ className, ...props }: React.ComponentProps<"nav">) {
  return (
    <nav
      data-slot="stepper-list"
      className={cn(
        "flex",
        "group-data-[orientation=horizontal]/stepper:flex-row group-data-[orientation=horizontal]/stepper:items-center",
        "group-data-[orientation=vertical]/stepper:flex-col group-data-[orientation=vertical]/stepper:items-start",
        className
      )}
      {...props}
    />
  )
}

type StepperItemProps = {
  step: number
} & React.ComponentProps<"div">

function StepperItem({ step, className, ...props }: StepperItemProps) {
  const { value } = useStepper()
  const isActive = value === step
  const isCompleted = value > step
  const state = isActive ? "active" : isCompleted ? "completed" : "inactive"

  return (
    <StepperItemContext.Provider value={{ step, isActive, isCompleted }}>
      <div
        data-slot="stepper-item"
        data-state={state}
        className={cn(
          "group/stepper-item flex shrink-0 items-center gap-2",
          className
        )}
        {...props}
      />
    </StepperItemContext.Provider>
  )
}

function StepperTrigger({
  className,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange } = useStepper()
  const { step, isActive } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      aria-current={isActive ? "step" : undefined}
      onClick={() => onValueChange(step)}
      className={cn(
        "flex items-center gap-2 rounded-md p-1 text-left",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
        "disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      {...props}
    />
  )
}

function StepperIndicator({
  className,
  ...props
}: React.ComponentProps<"span">) {
  const { step, isCompleted } = useStepperItem()

  return (
    <span
      data-slot="stepper-indicator"
      className={cn(
        "flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-medium transition-colors",
        "border-muted-foreground/30 bg-background text-muted-foreground",
        "group-data-[state=active]/stepper-item:border-primary group-data-[state=active]/stepper-item:bg-primary group-data-[state=active]/stepper-item:text-primary-foreground",
        "group-data-[state=completed]/stepper-item:border-primary group-data-[state=completed]/stepper-item:bg-primary group-data-[state=completed]/stepper-item:text-primary-foreground",
        className
      )}
      {...props}
    >
      {isCompleted ? <CheckIcon className="size-4" /> : step}
    </span>
  )
}

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("text-sm font-medium", className)}
      {...props}
    />
  )
}

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="stepper-separator"
      className={cn(
        "bg-muted-foreground/30",
        "group-data-[orientation=horizontal]/stepper:h-px group-data-[orientation=horizontal]/stepper:flex-1",
        "group-data-[orientation=vertical]/stepper:ms-4 group-data-[orientation=vertical]/stepper:h-8 group-data-[orientation=vertical]/stepper:w-px",
        className
      )}
      {...props}
    />
  )
}

type StepperPanelProps = {
  step: number
} & React.ComponentProps<"div">

function StepperPanel({ step, className, ...props }: StepperPanelProps) {
  const { value } = useStepper()
  if (value !== step) return null

  return (
    <div
      data-slot="stepper-panel"
      className={cn("flex-1", className)}
      {...props}
    />
  )
}

